const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;
    const componentCounts: Record<string, number> = {};
    for (const item of step.items) {
      if (COMPONENT_TYPES.has(item.type)) {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      } else {
        basePremium += BASE_PREMIUMS[item.type];
      }
    }
    for (const [type, count] of Object.entries(componentCounts)) {
      if (count === 3) {
        basePremium += 60;
      } else {
        basePremium += count * BASE_PREMIUMS[type];
      }
    }
    const firstInsuranceSurcharge = basePremium * 0.1;
    const premium = Math.ceil(basePremium + firstInsuranceSurcharge) + 5;
    return { premium };
  });
  return { results };
}

